async function (id, selectedDay) {
  try {
    if (!selectedDay) throw "Dia inválido";
    const now = new Date();
    const nextDate = new Date(now.getFullYear(), now.getMonth() + 1, parseInt(selectedDay));
    const y = nextDate.getFullYear();
    const m = String(nextDate.getMonth() + 1).padStart(2, '0');
    const d = String(nextDate.getDate()).padStart(2, '0');
    const newDateStr = `${y}-${m}-${d}`;
    const list = appsmith.store.subscriptions || [];
    const updatedList = list.map(sub => sub.subscription_id === id ? {
      ...sub,
      expires_at: newDateStr
    } : sub);
    await storeValue("subscriptions", updatedList);
    if (appsmith.store.selectedSubscription?.subscription_id === id) {
      await storeValue("selectedSubscription", {
        ...appsmith.store.selectedSubscription,
        expires_at: newDateStr
      });
    }
    showAlert(`Vencimento atualizado: ${newDateStr}`, "success");
    closeModal("modal_vencimento_fatura");
  } catch (e) {
    showAlert("Erro: Data original mantida.", "error");
  }
}

