async function (newQuantity) {
  try {
    const current = appsmith.store.selectedSubscription;
    const list = appsmith.store.subscriptions || [];
    const targetDescription = "Licenças Produto 1";
    const qty = Number(newQuantity);
    if (!Number.isInteger(qty) || qty < 1) {
      throw new Error("A quantidade deve ser um número inteiro maior que zero.");
    }
    const updatedProducts = current.products.map(p => p.description === targetDescription ? {
      ...p,
      quantity: qty
    } : p);
    if (!current.products.some(p => p.description === targetDescription)) {
      throw new Error("O item 'Licenças Produto 1' não foi encontrado na lista.");
    }
    const updatedSelected = {
      ...current,
      products: updatedProducts
    };
    const updatedList = list.map(sub => sub.subscription_id === current.subscription_id ? updatedSelected : sub);
    await storeValue("selectedSubscription", updatedSelected);
    await storeValue("subscriptions", updatedList);
    showAlert("Quantidade atualizada com sucesso!", "success");
    closeModal("Modal_alterar_licenca");
  } catch (error) {
    showAlert(error.message, "error");
  }
}

