	allProducts: [
		{ label: "Produto 1", value: "Produto 1", price: 10000 },
		{ label: "Licenças Produto 1", value: "Licenças Produto 1", price: 5000 },
		{ label: "Produto 2", value: "Produto 2", price: 20000 },
		{ label: "Produto 3", value: "Produto 3", price: 30000 }
	],

	getAvailableProducts() {
		const currentProducts = appsmith.store.selectedSubscription?.products || [];
		const currentValues = currentProducts.map(p => p.description);
		const hasP2 = currentValues.includes("Produto 2");
		const hasP3 = currentValues.includes("Produto 3");
		return this.allProducts.filter(item => {
			if (currentValues.includes(item.value)) return false;
			// Regra de Incompatibilidade (P2 vs P3)
			if (item.value === "Produto 2" && hasP3) return false;
			if (item.value === "Produto 3" && hasP2) return false;
			return true;
		});
	},

