			);

			await storeValue("selectedSubscription", updatedSelected);
			await storeValue("subscriptions", updatedList);
			showAlert("Quantidade atualizada com sucesso!", "success");
			closeModal("Modal_alterar_licenca"); 

		} catch (error) {
			showAlert(error.message, "error");
		}
	},

	async deleteProduct(productDescription) {
		try {
			const current = appsmith.store.selectedSubscription;
			const list = appsmith.store.subscriptions || [];
			const updatedProducts = current.products.filter(p => 
				p.description !== productDescription
			);

			const updatedSelected = { ...current, products: updatedProducts };

			const updatedList = list.map(sub => 
				sub.subscription_id === current.subscription_id ? updatedSelected : sub
			);

			await storeValue("selectedSubscription", updatedSelected);
			await storeValue("subscriptions", updatedList);

			showAlert("Produto removido.", "info");
			closeModal("modal_excluir");
		} catch (error) {
			closeModal("modal_excluir");
			showAlert("Erro ao remover.", "error");
		}
	}
}

